ValidationRule.errorConditionFormula:
AND(
    ISNEW(),
    OR(
        NOT(ISPICKVAL(Placement__r.Placement_Status__c, "Confirmed")),
        ISBLANK(Placement__r.Current_Project__c),
        ISBLANK(Placement__r.Candidate__c),
        /* Use the API Name here, not the 00N ID! */
        BLANKVALUE(Placement__r.Regular_Bill_Rate__c, 0) <= 0
    )
)
